    let seq = Array.from({length: 26}, (_, i) => {
        return (count[i] >= k) ? String.fromCharCode(i + 'a'.charCodeAt(0)).repeat(count[i] / k) : '';
    }).join('');

    function dp(i, j, memo = new Map()) {
        if (memo.has(`${i},${j}`)) return memo.get(`${i},${j}`);
        if (i >= seq.length || j >= seq.length) return 0;
        let res = (seq[i] === seq[j]) ? 1 + dp(i + 1, j + 1, memo) : Math.max(dp(i + 1, j, memo), dp(i, j + 1, memo));
        memo.set(`${i},${j}`, res);
        return res;
    }

    let res = [];
    let i = 0, j = 0;
    while (j < seq.length && res.length < seq.length / k) {
        if (res.length === 0 || seq[j] > res[res.length - 1]) {
            if (dp(i, j) >= (seq.length / k - res.length) * 2) {
                res.push(seq[j]);
                i = j + 1;
            }
        }
        j++;
    }

    return res.join('');
}
