import java.util.Arrays;

public String longestSubsequenceRepeatedK(String s, int k) {
    int[] count = new int[26];
    for (int i = 0; i < s.length(); i++) count[s.charAt(i) - 'a']++;
    StringBuilder seq = new StringBuilder();
    for (int i = 0; i < 26; i++) {
        if (count[i] >= k) seq.append(String.valueOf((char) ('a' + i)).repeat(count[i] / k));
    }
    int[][] dp = new int[seq.length() + 1][seq.length() + 1];
    for (int[] row : dp) Arrays.fill(row, 0);
    for (int i = seq.length() - 1; i >= 0; i--) {
        for (int j = i + 1; j < seq.length(); j++) {
            if (seq.charAt(i) == seq.charAt(j)) dp[i][j] = dp[i + 1][j + 1] + 1;
            else dp[i][j] = Math.max(dp[i + 1][j], dp[i][j + 1]);
        }
    }
    StringBuilder res = new StringBuilder();
    int i = 0, j = 0;
    while (j < seq.length() && res.length() < seq.length() / k) {
        if (res.length() == 0 || seq.charAt(j) > res.charAt(res.length() - 1)) {
            if (dp[i][j] >= (seq.length() / k - res.length()) * 2) {
                res.append(seq.charAt(j));
                i = j + 1;
            }
        }
        j++;
    }
    return res.toString();
}
